const player=document.querySelector('#player');function configure(){player.configure({platformUrl:'https://www.youtube.com/',openLabel:'Open YouTube',placeholder:'Paste a YouTube video or playlist URL'})}player.addEventListener('media-embed-ready',configure,{once:true});player.addEventListener('media-open-platform',event=>globalThis.open(event.detail.url,'_blank','noopener,noreferrer'));if(player.ready)configure();
